// ═══════════════════════════════════════════════════════════════════
// SYNESTHETIC SINGULARITY 2.0 - Flow field particle system
// Synthograsizer Workflow Template
// Created by Alexander Heemskerk, in collaboration with chatGPT, 2024
// ═══════════════════════════════════════════════════════════════════

const CW = 512;

// ─── PALETTES ────────────────────────────────────────────────────
const PALETTES = {
  neon:       ["#ff073a","#fe7f92","#fffb00","#08f7fe","#09fbd3"],
