  nes:        ["#ff0040","#0000d7","#d70039","#e4d00a","#006413"],
  rainbow:    ["#ff0000","#ffa500","#ffff00","#008000","#0000ff"],
  greyscale:  ["#222222","#555555","#888888","#bbbbbb","#eeeeee"],
  sunset:     ["#ff5e57","#ffac81","#ffcc70","#c2ff68","#80ffea"],
  ocean:      ["#03045e","#0077b6","#00b4d8","#90e0ef","#caf0f8"],
