// ─── MARGIN MAP ───────────────────────────────────────────────────
const MARGINS = {
  regular:  0.11,
  regular2: 0.08,
  huge:     0.01,
  square:   0.15
};

// ─── STATE ────────────────────────────────────────────────────────
let flowField;
let particles = [];
let zoff = 0;
let scale = 12;
let cols, rows;
let noiseScale = 0.005;

// tracked previous values to detect changes requiring reinit
let _prevPaletteName  = null;
let _prevBackground   = null;
let _prevMaxParticles = null;

// ─── SETUP ────────────────────────────────────────────────────────
p.setup = function() {
  p.createCanvas(CW, CW);

  cols = p.floor(CW / scale);
  rows = p.floor(CW / scale);
  flowField = new Array(cols * rows);

  // Read initial vars and build scene
  initScene();
};

// ─── initScene: (re)draw background, (re)spawn particles ─────────
function initScene() {
  let paletteName    = p.getSynthVar('palette')    || 'neon';
  let bgMode         = p.getSynthVar('background') || 'contrasting';
  let maxParticles   = parseInt(p.getSynthVar('maxparticles')) || 200;
  let palette        = PALETTES[paletteName] || PALETTES['neon'];

  _prevPaletteName  = paletteName;
  _prevBackground   = bgMode;
  _prevMaxParticles = maxParticles;

  // Draw gradient base
  for (let i = 0; i < CW; i++) {
    let inter = p.map(i, 0, CW, 0, 1);
    let c = p.lerpColor(p.color("#000000"), p.color("#ffffff"), inter);
    p.stroke(c);
    p.line(0, i, CW, i);
  }

  // Drop-shadow framed box
  p.drawingContext.shadowOffsetX = 5;
  p.drawingContext.shadowOffsetY = 5;
  p.drawingContext.shadowBlur    = 10;
  p.drawingContext.shadowColor   = "black";
  p.fill(50);
  p.noStroke();
  p.rectMode(p.CENTER);
  p.rect(CW / 2, CW / 2, CW - 100, CW - 100);
  p.drawingContext.shadowOffsetX = 1;
  p.drawingContext.shadowOffsetY = 1;
  p.drawingContext.shadowBlur    = 1;

  // Background colour
  applyBackground(bgMode, palette);

  p.noFill();

  // Spawn particles
  particles = [];
  for (let i = 0; i < maxParticles; i++) {
    particles.push(new Particle(palette[p.floor(p.random(palette.length))]));
  }
}

function applyBackground(bgMode, palette) {
  switch (bgMode) {
    case 'contrasting': p.background(palette[p.floor(p.random(palette.length))]); break;
    case 'white':       p.background(255);           break;
    case 'black':       p.background(0);             break;
    case 'gray':        p.background(127);           break;
    case 'gold':        p.background(255, 215, 0);   break;
    default:            p.background(255);
  }
}

// ─── DRAW ─────────────────────────────────────────────────────────
p.draw = function() {
  // Read all vars every frame
  let paletteName  = p.getSynthVar('palette')      || 'neon';
  let bgMode       = p.getSynthVar('background')   || 'contrasting';
  let maxParticles = parseInt(p.getSynthVar('maxparticles')) || 200;
  let chaos        = parseFloat(p.getSynthVar('chaos'))      || 0.5;
  let marginKey    = p.getSynthVar('Margin')                 || 'regular';
  let palette      = PALETTES[paletteName] || PALETTES['neon'];

  // Reinit if background or particle count changed
  if (bgMode !== _prevBackground || maxParticles !== _prevMaxParticles) {
    initScene();
    return;
  }

  // Re-colour existing particles when palette changes
  if (paletteName !== _prevPaletteName) {
    for (let particle of particles) {
      particle.color = palette[p.floor(p.random(palette.length))];
    }
    _prevPaletteName = paletteName;
  }

  generateFrame(chaos, marginKey, palette);
};

// ─── FLOW FIELD + PARTICLE STEP ───────────────────────────────────
function generateFrame(chaos, marginKey, palette) {
  let yoff = 0;
  for (let y = 0; y < rows; y++) {
    let xoff = 0;
    for (let x = 0; x < cols; x++) {
      let index = x + y * cols;
      let angle = p.noise(xoff, yoff, zoff) * p.TWO_PI * chaos;
      let v = p5.Vector.fromAngle(angle);
      v.setMag(1);
      flowField[index] = v;
      xoff += noiseScale;
    }
    yoff += noiseScale;
  }

  for (let particle of particles) {
    particle.follow(flowField);
    particle.update();
    particle.edges(marginKey);
    particle.show();
  }

  zoff += 0.005;
}

// ─── PARTICLE CLASS ───────────────────────────────────────────────
class Particle {
  constructor(col) {
    this.pos = p.createVector(
      p.random(CW * 0.1, CW * 0.9),
      p.random(CW * 0.1, CW * 0.9)
    );
    this.vel      = p.createVector(0, 0);
    this.acc      = p.createVector(0, 0);
    this.color    = col;
    this.maxSpeed = p.random(2, 5);
    this.prevPos  = this.pos.copy();
  }

  follow(vectors) {
    let x = p.floor(this.pos.x / scale);
    let y = p.floor(this.pos.y / scale);
    let index = x + y * cols;
    let force = vectors[index];
    if (force) this.applyForce(force);
  }

  applyForce(force) { this.acc.add(force); }

  update() {
    this.vel.add(this.acc);
    this.vel.limit(this.maxSpeed);
    this.pos.add(this.vel);
    this.acc.mult(0);
  }

  edges(marginKey) {
    let margin  = MARGINS[marginKey] || MARGINS['regular'];
    let wrapped = false;
    if (this.pos.x > CW * (1 - margin)) { this.pos.x = CW * margin;       wrapped = true; }
    if (this.pos.x < CW * margin)        { this.pos.x = CW * (1 - margin); wrapped = true; }
    if (this.pos.y > CW * (1 - margin)) { this.pos.y = CW * margin;       wrapped = true; }
    if (this.pos.y < CW * margin)        { this.pos.y = CW * (1 - margin); wrapped = true; }
    if (wrapped) this.updatePrev();
  }

  show() {
    p.stroke(this.color);
    p.strokeWeight(p.random(3, 12));
    p.line(this.prevPos.x, this.prevPos.y, this.pos.x, this.pos.y);
    this.updatePrev();
  }

  updatePrev() {
    this.prevPos.x = this.pos.x;
    this.prevPos.y = this.pos.y;
  }
}
